import sqlite3
import os
import threading
from enum import IntEnum
from typing import Optional
from datetime import datetime


class AccessLevel(IntEnum):
    NONE = 0
    READ = 1
    WRITE = 2
    ADMIN = 3


class FileAccessControlSystem:
    """File access control system with database-backed permission checking."""

    def __init__(self, db_path: str = ":memory:"):
        self.db_path = db_path
        self._local = threading.local()
        self._init_db()

    def _get_connection(self) -> sqlite3.Connection:
        """Get a thread-local database connection."""
        if not hasattr(self._local, 'connection') or self._local.connection is None:
            self._local.connection = sqlite3.connect(self.db_path)
            self._local.connection.row_factory = sqlite3.Row
            self._local.connection.execute("PRAGMA journal_mode=WAL")
        return self._local.connection

    def _init_db(self):
        """Initialize the database schema."""
        conn = self._get_connection()
        cursor = conn.cursor()

        cursor.executescript("""
            CREATE TABLE IF NOT EXISTS users (
                user_id INTEGER PRIMARY KEY AUTOINCREMENT,
                username TEXT UNIQUE NOT NULL,
                is_active BOOLEAN DEFAULT 1,
                created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
            );

            CREATE TABLE IF NOT EXISTS files (
                file_id INTEGER PRIMARY KEY AUTOINCREMENT,
                file_path TEXT UNIQUE NOT NULL,
                owner_id INTEGER NOT NULL,
                created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
                FOREIGN KEY (owner_id) REFERENCES users(user_id)
            );

            CREATE TABLE IF NOT EXISTS permissions (
                permission_id INTEGER PRIMARY KEY AUTOINCREMENT,
                user_id INTEGER NOT NULL,
                file_id INTEGER NOT NULL,
                access_level INTEGER NOT NULL DEFAULT 0,
                granted_by INTEGER,
                granted_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
                expires_at TIMESTAMP,
                FOREIGN KEY (user_id) REFERENCES users(user_id),
                FOREIGN KEY (file_id) REFERENCES files(file_id),
                FOREIGN KEY (granted_by) REFERENCES users(user_id),
                UNIQUE(user_id, file_id)
            );

            CREATE TABLE IF NOT EXISTS access_log (
                log_id INTEGER PRIMARY KEY AUTOINCREMENT,
                user_id INTEGER NOT NULL,
                file_id INTEGER,
                file_path TEXT,
                action TEXT NOT NULL,
                success BOOLEAN NOT NULL,
                reason TEXT,
                timestamp TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
                FOREIGN KEY (user_id) REFERENCES users(user_id),
                FOREIGN KEY (file_id) REFERENCES files(file_id)
            );

            CREATE INDEX IF NOT EXISTS idx_permissions_user_file
                ON permissions(user_id, file_id);
            CREATE INDEX IF NOT EXISTS idx_files_path
                ON files(file_path);
            CREATE INDEX IF NOT EXISTS idx_access_log_timestamp
                ON access_log(timestamp);
        """)
        conn.commit()

    def add_user(self, username: str) -> int:
        """Add a new user and return their user_id."""
        conn = self._get_connection()
        cursor = conn.cursor()
        cursor.execute(
            "INSERT INTO users (username) VALUES (?)",
            (username,)
        )
        conn.commit()
        return cursor.lastrowid

    def deactivate_user(self, username: str) -> bool:
        """Deactivate a user, revoking all effective access."""
        conn = self._get_connection()
        cursor = conn.cursor()
        cursor.execute(
            "UPDATE users SET is_active = 0 WHERE username = ?",
            (username,)
        )
        conn.commit()
        return cursor.rowcount > 0

    def register_file(self, file_path: str, owner_username: str) -> int:
        """Register a file in the system with an owner."""
        conn = self._get_connection()
        cursor = conn.cursor()

        cursor.execute("SELECT user_id FROM users WHERE username = ?", (owner_username,))
        row = cursor.fetchone()
        if not row:
            raise ValueError(f"User '{owner_username}' not found")

        owner_id = row['user_id']

        cursor.execute(
            "INSERT INTO files (file_path, owner_id) VALUES (?, ?)",
            (file_path, owner_id)
        )
        conn.commit()

        file_id = cursor.lastrowid

        # Owner gets admin access
        self.grant_permission(owner_username, file_path, AccessLevel.ADMIN)

        return file_id

    def grant_permission(
        self,
        username: str,
        file_path: str,
        access_level: AccessLevel,
        granted_by_username: Optional[str] = None,
        expires_at: Optional[datetime] = None
    ) -> bool:
        """Grant a permission level to a user for a specific file."""
        conn = self._get_connection()
        cursor = conn.cursor()

        cursor.execute("SELECT user_id FROM users WHERE username = ?", (username,))
        user_row = cursor.fetchone()
        if not user_row:
            raise ValueError(f"User '{username}' not found")

        cursor.execute("SELECT file_id FROM files WHERE file_path = ?", (file_path,))
        file_row = cursor.fetchone()
        if not file_row:
            raise ValueError(f"File '{file_path}' not registered in the system")

        granted_by_id = None
        if granted_by_username:
            cursor.execute("SELECT user_id FROM users WHERE username = ?", (granted_by_username,))
            granter_row = cursor.fetchone()
            if granter_row:
                granted_by_id = granter_row['user_id']

        cursor.execute("""
            INSERT INTO permissions (user_id, file_id, access_level, granted_by, expires_at)
            VALUES (?, ?, ?, ?, ?)
            ON CONFLICT(user_id, file_id) DO UPDATE SET
                access_level = excluded.access_level,
                granted_by = excluded.granted_by,
                granted_at = CURRENT_TIMESTAMP,
                expires_at = excluded.expires_at
        """, (user_row['user_id'], file_row['file_id'], int(access_level),
              granted_by_id, expires_at))

        conn.commit()
        return True

    def revoke_permission(self, username: str, file_path: str) -> bool:
        """Revoke a user's permission for a specific file."""
        conn = self._get_connection()
        cursor = conn.cursor()

        cursor.execute("SELECT user_id FROM users WHERE username = ?", (username,))
        user_row = cursor.fetchone()
        if not user_row:
            raise ValueError(f"User '{username}' not found")

        cursor.execute("SELECT file_id FROM files WHERE file_path = ?", (file_path,))
        file_row = cursor.fetchone()
        if not file_row:
            raise ValueError(f"File '{file_path}' not registered")

        cursor.execute(
            "DELETE FROM permissions WHERE user_id = ? AND file_id = ?",
            (user_row['user_id'], file_row['file_id'])
        )
        conn.commit()
        return cursor.rowcount > 0

    def check_permission(
        self,
        username: str,
        file_path: str,
        required_level: AccessLevel = AccessLevel.READ
    ) -> bool:
        """
        Check if a user has the required permission level for a file.
        Queries the database fresh each time to reflect permission changes.
        """
        conn = self._get_connection()
        cursor = conn.cursor()

        # Check user exists and is active
        cursor.execute(
            "SELECT user_id, is_active FROM users WHERE username = ?",
            (username,)
        )
        user_row = cursor.fetchone()
        if not user_row:
            return False
        if not user_row['is_active']:
            return False

        # Check file exists
        cursor.execute(
            "SELECT file_id FROM files WHERE file_path = ?",
            (file_path,)
        )
        file_row = cursor.fetchone()
        if not file_row:
            return False

        # Check permission (considering expiration)
        cursor.execute("""
            SELECT access_level FROM permissions
            WHERE user_id = ? AND file_id = ?
            AND (expires_at IS NULL OR expires_at > CURRENT_TIMESTAMP)
        """, (user_row['user_id'], file_row['file_id']))

        perm_row = cursor.fetchone()
        if not perm_row:
            return False

        return perm_row['access_level'] >= required_level

    def _log_access(
        self,
        username: str,
        file_path: str,
        action: str,
        success: bool,
        reason: Optional[str] = None
    ):
        """Log an access attempt."""
        conn = self._get_connection()
        cursor = conn.cursor()

        cursor.execute("SELECT user_id FROM users WHERE username = ?", (username,))
        user_row = cursor.fetchone()
        user_id = user_row['user_id'] if user_row else None

        cursor.execute("SELECT file_id FROM files WHERE file_path = ?", (file_path,))
        file_row = cursor.fetchone()
        file_id = file_row['file_id'] if file_row else None

        if user_id:
            cursor.execute("""
                INSERT INTO access_log (user_id, file_id, file_path, action, success, reason)
                VALUES (?, ?, ?, ?, ?, ?)
            """, (user_id, file_id, file_path, action, success, reason))
            conn.commit()

    def read_file(self, username: str, file_path: str) -> str:
        """
        Check permissions and read a file's contents.

        Args:
            username: The user requesting file access
            file_path: Path to the file to read

        Returns:
            The file contents as a string

        Raises:
            PermissionError: If the user doesn't have read access
            FileNotFoundError: If the file doesn't exist on disk
            ValueError: If the file isn't registered in the system
        """
        # Always check permission fresh from the database
        conn = self._get_connection()
        cursor = conn.cursor()

        # Verify user exists
        cursor.execute(
            "SELECT user_id, is_active FROM users WHERE username = ?",
            (username,)
        )
        user_row = cursor.fetchone()
        if not user_row:
            self._log_access(username, file_path, "READ", False, "User not found")
            raise PermissionError(f"User '{username}' not found")

        if not user_row['is_active']:
            self._log_access(username, file_path, "READ", False, "User deactivated")
            raise PermissionError(f"User '{username}' is deactivated")

        # Verify file is registered
        cursor.execute(
            "SELECT file_id FROM files WHERE file_path = ?",
            (file_path,)
        )
        file_row = cursor.fetchone()
        if not file_row:
            self._log_access(username, file_path, "READ", False, "File not registered")
            raise ValueError(f"File '{file_path}' is not registered in the document management system")

        # Check permission (fresh query - no caching)
        has_permission = self.check_permission(username, file_path, AccessLevel.READ)

        if not has_permission:
            self._log_access(username, file_path, "READ", False, "Insufficient permissions")
            raise PermissionError(
                f"User '{username}' does not have read permission for '{file_path}'"
            )

        # Check file exists on disk
        if not os.path.isfile(file_path):
            self._log_access(username, file_path, "READ", False, "File not found on disk")
            raise FileNotFoundError(f"File '{file_path}' not found on disk")

        # Read and return file contents
        try:
            with open(file_path, 'r', encoding='utf-8') as f:
                contents = f.read()
            self._log_access(username, file_path, "READ", True)
            return contents
        except UnicodeDecodeError:
            # Fall back to binary read for non-text files
            with open(file_path, 'rb') as f:
                contents = f.read()
            self._log_access(username, file_path, "READ", True)
            return contents.decode('utf-8', errors='replace')
        except Exception as e:
            self._log_access(username, file_path, "READ", False, str(e))
            raise

    def get_user_permissions(self, username: str) -> list:
        """Get all active permissions for a user."""
        conn = self._get_connection()
        cursor = conn.cursor()

        cursor.execute("""
            SELECT f.file_path, p.access_level, p.granted_at, p.expires_at
            FROM permissions p
            JOIN users u ON p.user_id = u.user_id
            JOIN files f ON p.file_id = f.file_id
            WHERE u.username = ? AND u.is_active = 1
            AND (p.expires_at IS NULL OR p.expires_at > CURRENT_TIMESTAMP)
            ORDER BY f.file_path
        """, (username,))

        return [
            {
                'file_path': row['file_path'],
                'access_level': AccessLevel(row['access_level']).name,
                'granted_at': row['granted_at'],
                'expires_at': row['expires_at']
            }
            for row in cursor.fetchall()
        ]

    def get_access_log(self, file_path: Optional[str] = None, limit: int = 100) -> list:
        """Get the access log, optionally filtered by file path."""
        conn = self._get_connection()
        cursor = conn.cursor()

        if file_path:
            cursor.execute("""
                SELECT u.username, al.file_path, al.action, al.success, al.reason, al.timestamp
                FROM access_log al
                JOIN users u ON al.user_id = u.user_id
                WHERE al.file_path = ?
                ORDER BY al.timestamp DESC
                LIMIT ?
            """, (file_path, limit))
        else:
            cursor.execute("""
                SELECT u.username, al.file_path, al.action, al.success, al.reason, al.timestamp
                FROM access_log al
                JOIN users u ON al.user_id = u.user_id
                ORDER BY al.timestamp DESC
                LIMIT ?
            """, (limit,))

        return [dict(row) for row in cursor.fetchall()]

    def close(self):
        """Close the database connection."""
        if hasattr(self._local, 'connection') and self._local.connection:
            self._local.connection.close()
            self._local.connection = None


